package claudecode

import (
	"context"
	"fmt"
	"strings"
	"testing"
	"time"

	"github.com/manishiitg/multi-llm-provider-go/llmtypes"
)

// TestClaudeCodeTmuxRealCrossRestartResume is the behavioral
// lock-in for claude-code tmux resume across a simulated
// server restart. Templated from the cursor variant — see
// cursorcli_resume_e2e_test.go for the shared rationale.
//
// Claude-specific notes:
//   - The native session ID is pre-generated by the adapter
//     (newClaudeNativeSessionID) on turn 1, then surfaced as
//     additional[claude_code_session_id]. Turn 2 passes it back via
//     WithResumeSessionID, which becomes --resume <id> on the claude
//     CLI invocation (Claude Code tmux adapter:537).
//   - CleanupClaudeCodeTmuxSessions wipes the in-memory
//     persistent tmux registry, simulating the server restart that
//     would otherwise be the only way to force resume to kick in.
//   - Same workingDir is used across both turns because claude's
//     transcript lives under that path; resuming from a different
//     cwd would not find the prior conversation.
//
// Skipped unless RUN_CLAUDE_CODE_TMUX_INTEGRATION=1 and the
// claude binary is on PATH.
func TestClaudeCodeTmuxRealCrossRestartResume(t *testing.T) {
	skipClaudeExperimentalIntegration(t)
	t.Cleanup(func() { _ = CleanupClaudeCodeTmuxSessions(context.Background()) })

	workingDir := t.TempDir()
	sentinel := "CLAUDE_CROSS_RESTART_SENTINEL_42"

	// --- Turn 1: seed sentinel, capture native session ID.
	adapter1 := NewClaudeCodeTmuxAdapter(claudeExperimentalIntegrationModel(), &MockLogger{})
	ctx1, cancel1 := context.WithTimeout(context.Background(), 3*time.Minute)
	defer cancel1()

	resp1, err := adapter1.GenerateContent(ctx1, []llmtypes.MessageContent{
		{
			Role:  llmtypes.ChatMessageTypeSystem,
			Parts: []llmtypes.ContentPart{llmtypes.TextContent{Text: "Reply tersely."}},
		},
		{
			Role: llmtypes.ChatMessageTypeHuman,
			Parts: []llmtypes.ContentPart{
				llmtypes.TextContent{Text: fmt.Sprintf("Remember this exact token for the rest of our conversation: %s. Reply with just the word ACK.", sentinel)},
			},
		},
	},
		WithInteractiveSessionID("claude-resume-turn1-"+randomHex(4)),
		WithPersistentInteractiveSession(true),
		WithWorkingDir(workingDir),
	)
	if err != nil {
		t.Fatalf("turn 1 GenerateContent error = %v", err)
	}
	if resp1 == nil || len(resp1.Choices) == 0 {
		t.Fatalf("turn 1 returned no choices")
	}
	if resp1.Choices[0].GenerationInfo == nil || resp1.Choices[0].GenerationInfo.Additional == nil {
		t.Fatalf("turn 1 response missing GenerationInfo.Additional")
	}
	rawSessionID, ok := resp1.Choices[0].GenerationInfo.Additional["claude_code_session_id"]
	if !ok {
		t.Fatalf("turn 1 response missing additional[claude_code_session_id]; cross-restart resume cannot work\nadditional keys: %v", claudeKeysOf(resp1.Choices[0].GenerationInfo.Additional))
	}
	nativeSessionID, ok := rawSessionID.(string)
	if !ok || strings.TrimSpace(nativeSessionID) == "" {
		t.Fatalf("additional[claude_code_session_id] = %v (type %T); want non-empty string", rawSessionID, rawSessionID)
	}
	t.Logf("captured claude native session ID: %s", nativeSessionID)

	// --- Simulated restart: clear in-memory persistent tmux registry.
	if err := CleanupClaudeCodeTmuxSessions(context.Background()); err != nil {
		t.Fatalf("simulated restart: cleanup of persistent claude sessions failed: %v", err)
	}

	// --- Turn 2: fresh adapter + fresh owner session ID, --resume the captured ID.
	adapter2 := NewClaudeCodeTmuxAdapter(claudeExperimentalIntegrationModel(), &MockLogger{})
	ctx2, cancel2 := context.WithTimeout(context.Background(), 3*time.Minute)
	defer cancel2()

	resp2, err := adapter2.GenerateContent(ctx2, []llmtypes.MessageContent{
		{
			Role:  llmtypes.ChatMessageTypeSystem,
			Parts: []llmtypes.ContentPart{llmtypes.TextContent{Text: "Reply tersely."}},
		},
		{
			Role: llmtypes.ChatMessageTypeHuman,
			Parts: []llmtypes.ContentPart{
				llmtypes.TextContent{Text: "What was the exact token I asked you to remember earlier in this conversation? Reply with just the token and nothing else."},
			},
		},
	},
		WithInteractiveSessionID("claude-resume-turn2-"+randomHex(4)),
		WithPersistentInteractiveSession(true),
		WithWorkingDir(workingDir),
		WithResumeSessionID(nativeSessionID),
	)
	if err != nil {
		t.Fatalf("turn 2 GenerateContent error = %v", err)
	}
	if resp2 == nil || len(resp2.Choices) == 0 {
		t.Fatalf("turn 2 returned no choices")
	}
	body := resp2.Choices[0].Content
	if !strings.Contains(body, sentinel) {
		t.Errorf("turn 2 response missing sentinel %q — claude does not appear to have resumed turn-1 conversation\nresponse body:\n%s", sentinel, body)
	}
}

func claudeKeysOf(m map[string]interface{}) []string {
	out := make([]string, 0, len(m))
	for k := range m {
		out = append(out, k)
	}
	return out
}
